+let closeResolve: (() => void) | undefined;
+
+vi.mock("../config/config.js", () => ({
+  loadConfig: () => config,
+}));
+
+vi.mock("../auto-reply/reply.js", () => ({
+  getReplyFromConfig: (...args: unknown[]) => replyMock(...args),
